SELECT SUM(heatrate_2008) AS total_heatrate_2008
FROM power_generation_technologies
WHERE fuel_type = 'Gas';

SELECT DISTINCT t.technology, s.equipment, s.materials
FROM power_generation_technologies AS t
JOIN technology_specifications AS s ON t.technology_id = s.technology_id;

SELECT technology, technology_description, fuel_type, total_overnight_cost, variable_om, emissions_data
FROM power_generation_technologies
WHERE technology_id = 3;

SELECT technology, size_mw
FROM power_generation_technologies
WHERE fixed_om = (SELECT MIN(fixed_om) FROM power_generation_technologies);

SELECT COUNT(DISTINCT technology_id) AS total_technologies
FROM technology_specifications
WHERE equipment LIKE '%Solar thermal collector%';

SELECT *
FROM power_generation_technologies
ORDER BY size_mw DESC, leadtimes_years DESC;

SELECT COUNT(*) AS total_scenarios
FROM scenario_plans
WHERE created_at >= date('now', '-30 days');

SELECT technology, fuel_type
FROM power_generation_technologies
ORDER BY size_mw DESC;

SELECT technology, fuel_type, base_overnight_costs
FROM power_generation_technologies
WHERE fuel_type = 'coal' AND base_overnight_costs > 5000;

SELECT sp.scenario_name, sp.variables, spv.variable_name, spv.value
FROM scenario_plans sp
JOIN scenario_planning_variables spv ON sp.scenario_id = spv.scenario_id;

SELECT scenario_id, scenario_name 
FROM scenario_plans
WHERE variables LIKE '%Inflation%' AND assumptions LIKE '%Future%';

SELECT user_id, COUNT(scenario_id) AS total_number_of_scenarios
FROM scenario_plans
GROUP BY user_id;
